// Robot Buddy — an unmistakably cute, friendly desktop robot.
// BREP showcase: every primitive is rounded with fillets/chamfers so the
// whole character reads as soft and adorable. One fused solid.
const { BREP } = api;

// ---- Legs / feet (two rounded stubby boxes on the ground) ----
const footW = 7, footD = 8, footH = 6;
const footGap = 9;           // center-to-center spacing
const footProto = BREP.box([footW, footD, footH]).fillet(2.4);
// Sink tops 1mm into the torso seam later (torso base sits at z=footH-1).
const footL = footProto.translate([-footGap / 2, 0, 0]);
const footR = footProto.translate([+footGap / 2, 0, 0]);

// ---- Torso (rounded boxy body) ----
const torsoW = 22, torsoD = 16, torsoH = 18;
const torsoZ0 = footH - 1;   // overlap feet by 1mm
const torso = BREP.box([torsoW, torsoD, torsoH])
  .fillet(4)
  .translate([0, 0, torsoZ0]);
const torsoTopZ = torsoZ0 + torsoH;

// ---- Neck (short cylinder bridging torso & head) ----
const neckR = 4, neckH = 3;
const neck = BREP.cylinder(neckR, neckH + 1.5).translate([0, 0, torsoTopZ - 1]);
const neckTopZ = torsoTopZ - 1 + neckH + 1.5;

// ---- Head (rounded cube) ----
const headW = 16, headD = 14, headH = 13;
const headZ0 = neckTopZ - 1.5;   // sink head onto the neck
const head = BREP.box([headW, headD, headH])
  .fillet(4)
  .translate([0, 0, headZ0]);
const headCZ = headZ0 + headH / 2;   // head center Z
const headFrontY = headD / 2;        // +Y face of head

// ---- Eyes (two spheres proud of the head front) ----
const eyeR = 3.1;
const eyeZ = headZ0 + headH * 0.60;
const eyeY = headFrontY - 1.2;       // bite into the face for a clean fuse
const eyeSep = 5.0;
const eyeL = BREP.sphere(eyeR).translate([-eyeSep, eyeY, eyeZ]);
const eyeR_ = BREP.sphere(eyeR).translate([+eyeSep, eyeY, eyeZ]);

// ---- Smile (a thin rounded bar across the lower face) ----
const mouthW = 8, mouthD = 2, mouthH = 1.8;
const mouthZ = headZ0 + headH * 0.30;
const mouth = BREP.box([mouthW, mouthD + 2, mouthH])
  .fillet(0.8)
  .translate([0, headFrontY - 1, mouthZ]);

// ---- Ears / side knobs (little cylinders on the head sides) ----
const earR = 2.2, earLen = 2.5;
const earZ = headZ0 + headH * 0.55;
const earProto = BREP.cylinder(earR, earLen + 1.5);
const earL = earProto.rotate(-90, [0, 1, 0]).translate([-headW / 2 + 1, 0, earZ]);
const earR_ = earProto.rotate(+90, [0, 1, 0]).translate([+headW / 2 - 1, 0, earZ]);

// ---- Arms (rounded boxes that stick out at the torso sides) ----
const armW = 4.5, armD = 5, armH = 11;
const armZ0 = torsoZ0 + 5;        // keep arm in the torso's flat mid-band
// Bite ~3.5mm into the torso so the fuse has solid volume, not a tangent kiss.
const armX = torsoW / 2 + armW / 2 - 3.5;
const armProto = BREP.box([armW, armD, armH]).fillet(1.9);
const armL = armProto.translate([-armX, 0, armZ0]);
const armR = armProto.translate([+armX, 0, armZ0]);
// Little hand balls on the bottom of each arm (overlap the arm box, not the torso).
const handR = 2.8;
const handX = armX + armW / 2 - 1.2;
const handL = BREP.sphere(handR).translate([-handX, 0, armZ0 + 0.5]);
const handR_ = BREP.sphere(handR).translate([+handX, 0, armZ0 + 0.5]);

// ---- Chest panel (a rounded inset bump on the torso front) ----
const panelW = 10, panelD = 2, panelH = 7;
const panelZ = torsoZ0 + torsoH * 0.45;
const panel = BREP.box([panelW, panelD + 2, panelH])
  .fillet(1.2)
  .translate([0, torsoD / 2 - 1, panelZ]);

// ---- Antenna (rod + bobble ball on the head top) ----
const antR = 0.7, antH = 6;
const antZ0 = headZ0 + headH - 1;
const antenna = BREP.cylinder(antR, antH).translate([0, 0, antZ0]);
const bobble = BREP.sphere(1.7).translate([0, 0, antZ0 + antH - 0.4]);

// ---- Assemble into one fused solid ----
// Face features sit on +Y; rotate 180° about Z so the face points toward the
// catalog thumbnail's default camera (which looks from the -Y side).
const robot = BREP.fuseAll([
  footL, footR,
  torso,
  neck,
  head,
  eyeL, eyeR_,
  mouth,
  earL, earR_,
  armL, armR, handL, handR_,
  panel,
  antenna, bobble,
]);
return robot.rotate(180, [0, 0, 1]);

